UPDATE "Show" SET "cast" = 'נתן דטנר אריק סיני יזהר כהן מיקי קם אלון עדר אפרת גוש בן ארצי עדי כהן בימוי ועריכה: עדו הכהן ניהול מוסיקלי: אוהד בן אבי בין שיריו הגדולים שיבוצעו במופע: "אין לי ארץ אחרת", "הלוואי", "ימי בנימינה", "ברית עולם", "ילדותי השנייה", "אבניבי", "סיבה טובה", "הייתי בגן עדן", "אם זו אהבה" ועוד' WHERE "slug" = 'אין-לי-ארץ-אחרת-מופע-הצדעה-לאהוד-מנור';
UPDATE "Show" SET "cast" = 'אבי גרייניק, עידן אלתרמן, מעין וינשטוק/דורון לוי, נועה טסה, איתי פולישוק, אסף דגני, שי אגוזי, אייל שרף' WHERE "slug" = 'הזוג-המוזר';
UPDATE "Show" SET "cast" = 'גילה אלמגור | רוני דלומי | נועם קליינשטיין | דודו פישר | דפנה דקל | נדיר אלדד עדן ביטון | אייל בוחבוט | דורון אדמוני | דניאל כהן | עדאל קורשוב | ים בורשטיין | גאיה אלבס | גיא סטרובולסקי' WHERE "slug" = 'היומן';
UPDATE "Show" SET "cast" = 'ציפי שביט, עידן אלתרמן/משה אשכנזי/עידו מוסרי, שלמה וישינסקי, עירית ענבי, נועה אנגל, מעין וינשטוק, קובי זיסלין' WHERE "slug" = 'לשחרר-את-נחמה';
UPDATE "Show" SET "cast" = 'אוולין הגואל, אריה צ''רנר / יוסף אבו ורדה, תקווה עזיז, נינה קוטלר, זהר שטראוס, עדנה בליליוס, הילה סעדה, נדיר אלדר, בר ברימר, לירי הפנר, דניאל גימפל, יונל יוסף' WHERE "slug" = 'לילסדה';
UPDATE "Show" SET "cast" = 'יפתח קליין, יעל שרוני, גל אמיתי, יובל שרף, סתיו זוהר דהן, אביה עבדי, יעלה ארבל, בנימין עציון, עמית ישראל, איליי גרינפלד - יונה' WHERE "slug" = 'המאסטר-(אלוף-הבונים-שלי)';
UPDATE "Show" SET "cast" = 'בן פרי, דיאנה גולבי, עידו מוסרי, איילת רובינסון' WHERE "slug" = 'משתגעים-מאהבה';
